PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE products (
	id INTEGER NOT NULL, 
	artikel_id VARCHAR(32) NOT NULL, 
	ean_gtin VARCHAR(32), 
	hersteller VARCHAR(128), 
	hersteller_artikelnr VARCHAR(64), 
	artikelname VARCHAR(256) NOT NULL, 
	artikelbeschreibung TEXT, 
	kategorie VARCHAR(64), 
	unterkategorie VARCHAR(64), 
	werkstoff VARCHAR(64), 
	nennweite_dn INTEGER, 
	nennweite_od INTEGER, 
	laenge_mm INTEGER, 
	breite_mm INTEGER, 
	hoehe_mm INTEGER, 
	wandstaerke_mm FLOAT, 
	gewicht_kg FLOAT, 
	belastungsklasse VARCHAR(16), 
	steifigkeitsklasse_sn VARCHAR(16), 
	norm_primaer VARCHAR(64), 
	norm_sekundaer VARCHAR(64), 
	system_familie VARCHAR(64), 
	verbindungstyp VARCHAR(64), 
	dichtungstyp VARCHAR(64), 
	kompatible_dn_anschluss VARCHAR(64), 
	kompatible_systeme VARCHAR(128), 
	einsatzbereich VARCHAR(128), 
	einbauort VARCHAR(64), 
	ek_netto FLOAT, 
	vk_listenpreis_netto FLOAT, 
	staffelpreis_ab_10 FLOAT, 
	staffelpreis_ab_50 FLOAT, 
	staffelpreis_ab_100 FLOAT, 
	waehrung VARCHAR(8), 
	preiseinheit VARCHAR(32), 
	lager_rheinbach INTEGER, 
	lager_duesseldorf INTEGER, 
	lager_gesamt INTEGER, 
	lieferant_1_lieferzeit_tage INTEGER, 
	status VARCHAR(32), 
	ersatz_artikel_id VARCHAR(32), 
	nachfolger_artikel_id VARCHAR(32), 
	PRIMARY KEY (id)
);
COMMIT;
